#!/usr/bin/env bash
set -euo pipefail

rm -rf android
base64 -d <<'ARCHIVE' | tar -xz

ARCHIVE

python3 <<'PYCODE'
from pathlib import Path
src = Path("index.html")
out = Path("android/app/src/main/assets/index.html")
s = src.read_text(encoding="utf-8")

s = s.replace(
    '  <a class="menu-item" id="offlineDownloadLink" href="./Nictionary_Offline.html" download="Nictionary_Offline.html">Download offline copy</a>\n',
    ''
)
s = s.replace('el("offlineDownloadLink").addEventListener("click",()=>closeDrawer(false));', '')

old_share = 'function openShareOptions(){if(!state.over)return toast("Finish the puzzle before sharing");el("shareModalPreview").textContent=resultGridText();el("nativeShareBtn").hidden=!navigator.share;openModal("shareModal")}async function shareViaDevice(){if(!navigator.share)return copyResultToClipboard();try{await navigator.share({title:"Nictionary",text:resultText()})}catch(error){if(error?.name!=="AbortError")toast("Could not open sharing options")}}async function copyResultToClipboard(){const text=resultText();try{if(navigator.clipboard&&location.protocol!=="file:"){await navigator.clipboard.writeText(text);toast("Result copied to clipboard")}else fallbackCopy(text)}catch{fallbackCopy(text)}}'
new_share = 'function openShareOptions(){if(!state.over)return toast("Finish the puzzle before sharing");el("shareModalPreview").textContent=resultGridText();el("nativeShareBtn").hidden=!(navigator.share||window.NictionaryNative);openModal("shareModal")}async function shareViaDevice(){if(window.NictionaryNative){NictionaryNative.shareText(resultText());return}if(!navigator.share)return copyResultToClipboard();try{await navigator.share({title:"Nictionary",text:resultText()})}catch(error){if(error?.name!=="AbortError")toast("Could not open sharing options")}}async function copyResultToClipboard(){const text=resultText();if(window.NictionaryNative){NictionaryNative.copyText(text);return}try{if(navigator.clipboard&&location.protocol!=="file:"){await navigator.clipboard.writeText(text);toast("Result copied to clipboard")}else fallbackCopy(text)}catch{fallbackCopy(text)}}'
if old_share not in s:
    raise SystemExit("Expected share integration block was not found in index.html")
s = s.replace(old_share, new_share, 1)

old_export = 'function exportData(){const payload={app:"Nictionary",appVersion:APP_VERSION,formatVersion:3,exportedAt:(new Date).toISOString(),data:{settings:settings,stats:stats,progress:progressStore,seenHelp:!!safeGet(STORAGE.seenHelp)}};try{const blob=new Blob([JSON.stringify(payload,null,2)],{type:"application/json"}),url=URL.createObjectURL(blob),link=document.createElement("a");link.href=url;link.download=`Nictionary_Backup_${todayKey()}.json`;document.body.appendChild(link);link.click();link.remove();setTimeout(()=>URL.revokeObjectURL(url),1e3);toast("Backup exported")}catch{toast("Could not create the backup file")}}'
new_export = 'function exportData(){const payload={app:"Nictionary",appVersion:APP_VERSION,formatVersion:3,exportedAt:(new Date).toISOString(),data:{settings:settings,stats:stats,progress:progressStore,seenHelp:!!safeGet(STORAGE.seenHelp)}},content=JSON.stringify(payload,null,2),filename=`Nictionary_Backup_${todayKey()}.json`;try{if(window.NictionaryNative){NictionaryNative.saveText(filename,content);return}const blob=new Blob([content],{type:"application/json"}),url=URL.createObjectURL(blob),link=document.createElement("a");link.href=url;link.download=filename;document.body.appendChild(link);link.click();link.remove();setTimeout(()=>URL.revokeObjectURL(url),1e3);toast("Backup exported")}catch{toast("Could not create the backup file")}}'
if old_export not in s:
    raise SystemExit("Expected export integration block was not found in index.html")
s = s.replace(old_export, new_export, 1)

out.parent.mkdir(parents=True, exist_ok=True)
out.write_text(s, encoding="utf-8")
PYCODE
